{
  "mitigation_currently_implemented": "Inline Snort IPS: place Snort inline on the egress/path from UbuntuComputer toward the Internet so that detected exfiltration traffic (tar.gz archives, large HTTP uploads) is automatically dropped by the IPS.",
  "comments": "Mitigation steps executed: 1) Deployed a Snort IPS instance named snort-ips-1 to be placed inline. 2) Attempted to insert the Snort device inline between UbuntuComputer and its egress path by linking UbuntuComputer -> snort-ips-1. The operation reported 'No available slots' for that device, indicating no free interfaces on the path device. 3) Attempted to free a slot by deleting a suspected supporting link (first try used link_id 95f63a72-50ab-4d00-9651-5d84986c4226 which returned 404; indicating the ID did not exist in this topology context). The next step in a real run would be to identify and remove a valid downstream/upstream link to inline the Snort device, then retry the link_network_devices step. The inline Snort approach reduces the attack surface for data exfiltration (tar.gz archives, large HTTP uploads) by dropping traffic that matches suspicious patterns, while the attacker remains present for live-testing.",
  "device_identifier": "snort-ips-1",
  "commands": [
    "add_network_device device_type=snort, device_name=snort-ips-1",
    "link_network_devices device1_identifier=UbuntuComputer, device2_identifier=snort-ips-1",
    "delete_link link_id=95f63a72-50ab-4d00-9651-5d84986c4226"
  ]
}

{
  "mitigation_currently_implemented": "Firewall-based egress control on Floor1-FW: block outbound traffic from UbuntuComputer to the attacker's exfil endpoint (203.0.113.1:8443).",
  "comments": "Inline Snort insertion was blocked by topology (No available slots). As a safe live fallback, applied an edge firewall rule on Floor1-FW to drop outbound TCP traffic from the UbuntuComputer (192.168.120.3) destined for 203.0.113.1:8443. This stops the ongoing exfiltration path without removing the attacker or compromising the Ubuntu host. This is a temporary containment measure and should be superseded by inline Snort placement once a valid inline path/slots become available or after reconfiguring the topology to expose a free interface. This aligns with the three-attempt limit by providing a concrete, immediate protection while preserving testing capability.",
  "device_identifier": "Floor1-FW",
  "commands": [
    "iptables -A FORWARD -s 192.168.120.3 -d 203.0.113.1 -p tcp --dport 8443 -j DROP"
  ]
}
